// Decide whether the current wind gusts warrant an alert.
// "Exceed" = strictly greater than the threshold (gusts > threshold).
//
// Pure function: no network or closure dependencies, so it is directly
// unit-testable. Takes the `current` conditions object from fetchWeather and a
// numeric threshold (knots), and returns the alert flag, the echoed gust value,
// the echoed threshold, and a short human-readable message.
function computeWindAlert(current: any, threshold: number) {
  // Coerce inputs defensively — current may lack windGusts (e.g. inland/null)
  const gusts = typeof current?.windGusts === 'number' ? current.windGusts : 0;
  const thresholdKn = typeof threshold === 'number' && !isNaN(threshold) ? threshold : 0;

  // Strictly-greater comparison: gusts must exceed the threshold to alert
  const alert = gusts > thresholdKn;

  // Round helper — keep displayed numbers to 1 decimal place
  const round1 = (n: number) => Math.round(n * 10) / 10;
  const gustsR = round1(gusts);
  const thresholdR = round1(thresholdKn);

  // Build a short human-readable message for each branch
  const message = alert
    ? `⚠️ Wind gusts of ${gustsR} kn exceed the ${thresholdR} kn threshold — strong gusts, sail with caution.`
    : `Wind gusts of ${gustsR} kn are within the ${thresholdR} kn threshold — conditions look manageable.`;

  return { alert, gusts: gustsR, threshold: thresholdR, message };
}
